const isWeekend = [0,6].includes(new Date().getDay());

const markets = $input.all().map(i => i.json);

const assetKeywords = {
  btc: ['bitcoin', 'btc'],
  eth: ['ethereum', 'eth price', 'ether ', 'eth hit', 'eth reach', 'eth above', 'eth to ', 'eth at ', 'eth cross', 'ethereum hit', 'ethereum reach', 'ethereum above'],
  gold: ['gold price', 'gold hit', 'price of gold', 'xau', 'gold above', 'gold reach', 'gold to ', 'gold at ', 'gold cross', 'gold exceed', 'gold surpass', 'gold breaks', 'gold past'],
  silver: ['silver price', 'silver hit', 'price of silver', 'xag', 'silver above', 'silver reach', 'silver to ', 'silver at ', 'silver cross', 'silver exceed', 'silver surpass'],
  wti: ['wti', 'crude oil price', 'west texas', 'crude oil', 'oil price', 'oil above', 'oil reach', 'oil hit'],
  brent: ['brent', 'brent crude', 'brent oil']
};

// Sports / non-commodity false positives
const sportsExclude = /stanley cup|nba|nfl|nhl|warriors|knights|oilers|lakers|nuggets|cavaliers|celtics|76ers|super bowl|world cup|premier league|championship|playoffs|olympics|finals|win the|grand prix|gold medal|gold cards|golden globe|golden bachelor|olympic gold/i;

// Sanity floor — prevents matching years/IDs as prices
const minPrice = { btc: 10000, eth: 500, gold: 1000, silver: 10, wti: 30, brent: 30 };

const triggerRegex = /(?:above|over|reach(?:es|ed)?|hit(?:s|ting)?|cross(?:es|ed)?|exceed(?:s|ed)?|surpass(?:es|ed)?|past|to|at)\s+\$?([\d,]+\.?\d*[kmb]?)/gi;

function parseNumeric(s) {
  const suffix = s.slice(-1).toLowerCase();
  const clean = s.replace(/[,kmb]/gi, '');
  const num = parseFloat(clean);
  if (!isFinite(num)) return null;
  if (suffix === 'k') return num * 1000;
  if (suffix === 'm') return num * 1000000;
  if (suffix === 'b') return num * 1000000000;
  return num;
}

const results = [];
const seen = new Set();

for (const m of markets) {
  const text = (m.question || '').toLowerCase();
  const desc = (m.description || '').toLowerCase();
  const fullText = text + ' ' + desc;
  const endDate = m.endDate || m.end_date_iso;
  const marketId = m.id || m.conditionId;

  if (seen.has(marketId)) continue;
  seen.add(marketId);

  if (sportsExclude.test(m.question || '')) continue;

  let asset = null;
  for (const [a, keywords] of Object.entries(assetKeywords)) {
    if (keywords.some(k => fullText.includes(k))) {
      asset = a;
      break;
    }
  }
  if (!asset) continue;
  if (isWeekend && asset !== 'btc' && asset !== 'eth') continue;

  // Primary: $-prefixed prices
  const dollarMatches = (text.match(/\$[\d,]+\.?\d*[kmb]?/gi) || []).map(p => p.replace('$',''));
  // Fallback: bare numbers following trigger words (commodity questions)
  const triggerMatches = [...text.matchAll(triggerRegex)].map(mm => mm[1]);

  const allMatches = [...dollarMatches, ...triggerMatches];
  const prices = allMatches.map(parseNumeric).filter(p => p !== null && p > 0);

  const floor = minPrice[asset] || 1;
  const valid = prices.filter(p => p >= floor);
  if (valid.length === 0) continue;

  const horizonDays = endDate
    ? Math.ceil((new Date(endDate) - new Date()) / 86400000)
    : 30;
  if (horizonDays <= 0 || horizonDays > 365) continue;

  let yesPrice = null;
  try {
    const p = typeof m.outcomePrices === 'string'
      ? JSON.parse(m.outcomePrices)
      : m.outcomePrices;
    if (p && p[0] !== undefined) yesPrice = parseFloat(p[0]);
  } catch (e) {}
  if (yesPrice === null || yesPrice < 0.02 || yesPrice > 0.98) continue;

  const targetPrice = Math.max(...valid);

  results.push({
    market_id: marketId,
    question: m.question,
    asset,
    target: targetPrice,
    yes_price: yesPrice,
    horizon_days: horizonDays,
    end_date: endDate,
    volume: parseFloat(m.volume || 0),
    needs_simulation: true,
    source: m.source || 'polymarket'
  });
}

results.sort((a, b) => b.volume - a.volume);

return results.map(r => ({ json: r }));

const HIGH_EDGE_THRESHOLD = 0.07;
const NO_EDGE_THRESHOLD = -0.10;
const MIN_ALERT_VOLUME = 5000;

const items = $input.all();
const highEdge = [];
const noEdge = [];
const neutral = [];
const sims = [];
let simErrors = 0;

for (let i = 0; i < items.length; i++) {
  const sim = items[i].json;
  let original;
  try {
    original = $('Analyse Edge').itemMatching(i).json;
  } catch (e) {
    simErrors++;
    continue;
  }

  const simProb = sim.probability !== undefined ? sim.probability : sim.sim_probability;
  if (simProb === undefined || simProb === null) {
    simErrors++;
    continue;
  }

  const edge = simProb - original.yes_price;
  const merged = {
    market_id: original.market_id,
    question: original.question,
    asset: original.asset,
    target: original.target,
    yes_price: original.yes_price,
    sim_probability: simProb,
    edge: edge * 100,
    horizon_days: original.horizon_days,
    end_date: original.end_date,
    volume: original.volume,
    source: original.source,
    daily_mu: sim.daily_mu,
    current_price: sim.current_price
  };

  if (edge >= HIGH_EDGE_THRESHOLD && original.volume >= MIN_ALERT_VOLUME) {
    highEdge.push(merged);
  } else if (edge <= NO_EDGE_THRESHOLD && original.volume >= MIN_ALERT_VOLUME) {
    noEdge.push(merged);
  } else {
    neutral.push(merged);
  }

  // Supabase trading_simulations row — column-aligned shape
  sims.push({
    asset: original.asset,
    simulation_count: sim.simulations || 10000,
    probability: simProb,
    current_price: sim.current_price !== undefined ? sim.current_price : null,
    edge: edge,
    implied_odds: original.yes_price,
    macro_factors: sim.macro_factors || null,
    confidence_lower: sim.confidence_lower !== undefined ? sim.confidence_lower : null,
    confidence_upper: sim.confidence_upper !== undefined ? sim.confidence_upper : null,
    raw_output: {
      polymarket_market_id: original.market_id,
      question: original.question,
      target: original.target,
      horizon_days: original.horizon_days,
      end_date: original.end_date,
      volume: original.volume,
      source: original.source,
      daily_mu: sim.daily_mu,
      daily_sigma: sim.daily_sigma,
      macro_adjustment: sim.macro_adjustment
    }
  });
}

let fetchedCount = 0;
try { fetchedCount = $('Merge Pages').all().length; } catch (e) {}
let passedFilter = 0;
try { passedFilter = $('Analyse Edge').all().length; } catch (e) {}

return [{
  json: {
    highEdge,
    noEdge,
    neutral,
    stats: {
      run_at: new Date().toISOString(),
      fetched: fetchedCount,
      passed_filter: passedFilter,
      markets_simulated: items.length,
      sim_errors: simErrors,
      high_edge_count: highEdge.length,
      no_edge_count: noEdge.length,
      neutral_count: neutral.length
    },
    sims
  }
}];

